import{_ as s,C as n,o as e,c as o,a3 as l,b as d,w as i,a as p,E as r,a4 as c}from"./chunks/framework.DACwFHq9.js";const x=JSON.parse('{"title":"移动端 LLM 模型检查交互设计","description":"","frontmatter":{},"headers":[],"relativePath":"design/mobile-llm-model-probe-interaction-design.md","filePath":"design/mobile-llm-model-probe-interaction-design.md","lastUpdated":1784164122000}'),h={name:"design/mobile-llm-model-probe-interaction-design.md"};function u(b,a,m,E,_,A){const t=n("Mermaid");return e(),o("div",null,[a[1]||(a[1]=l('<h1 id="移动端-llm-模型检查交互设计" tabindex="-1">移动端 LLM 模型检查交互设计 <a class="header-anchor" href="#移动端-llm-模型检查交互设计" aria-label="Permalink to &quot;移动端 LLM 模型检查交互设计&quot;">​</a></h1><blockquote><p>状态：首批实现完成</p><p>日期：2026-07-16</p><p>关联计划：<a href="./../Plan/llm-channel-probe-improvement-plan"><code>docs/Plan/llm-channel-probe-improvement-plan.md</code></a></p></blockquote><h2 id="_1-设计结论" tabindex="-1">1. 设计结论 <a class="header-anchor" href="#_1-设计结论" aria-label="Permalink to &quot;1. 设计结论&quot;">​</a></h2><p>移动端不复刻桌面端的宽弹窗和表格式结果。模型检查应作为渠道编辑中的独立全屏任务页，复用当前未保存的渠道快照，并围绕三种核心任务组织：</p><ol><li>从模型列表快速检查单个模型。</li><li>选择多个模型后批量检查，并能随时停止。</li><li>在结果页快速定位失败项，再进入单项诊断详情。</li></ol><p>现有“从 API 获取”继续表示模型发现与导入，不作为推理健康检查，也不与模型检查结果混用。</p><h2 id="_2-设计定位" tabindex="-1">2. 设计定位 <a class="header-anchor" href="#_2-设计定位" aria-label="Permalink to &quot;2. 设计定位&quot;">​</a></h2><h3 id="_2-1-用户与场景" tabindex="-1">2.1. 用户与场景 <a class="header-anchor" href="#_2-1-用户与场景" aria-label="Permalink to &quot;2.1. 用户与场景&quot;">​</a></h3><p>目标用户是需要配置自定义渠道、排查端点和模型能力的技术用户。页面应强调可扫描、可中断、错误可追溯，不使用营销式大标题、装饰性卡片或高强度动效。</p><p>设计参数：</p><table tabindex="0"><thead><tr><th>维度</th><th style="text-align:right;">取值</th><th>说明</th></tr></thead><tbody><tr><td>差异度</td><td style="text-align:right;">3/10</td><td>保持现有设置页秩序和操作习惯</td></tr><tr><td>动效强度</td><td style="text-align:right;">2/10</td><td>只表现状态变化和页面转场</td></tr><tr><td>信息密度</td><td style="text-align:right;">7/10</td><td>技术信息较多，但通过分层避免首屏拥挤</td></tr></tbody></table><h3 id="_2-2-设计原则" tabindex="-1">2.2. 设计原则 <a class="header-anchor" href="#_2-2-设计原则" aria-label="Permalink to &quot;2.2. 设计原则&quot;">​</a></h3><ul><li>检查与编辑分离：检查页不修改模型和渠道配置。</li><li>快照优先：始终检查点击时的 <code>innerProfile</code> 深拷贝，不依赖保存或防抖完成。</li><li>结果就地可见：模型列表回显最近一次运行态结果，完整诊断进入详情页。</li><li>失败优先：批量结束后优先支持筛选和重试失败项。</li><li>成本显式：图片和音频必须二次确认，视频和音乐明确不可自动检查。</li><li>状态不只依赖颜色：图标、文字和颜色共同表达状态。</li><li>不保存敏感信息：结果、日志和复制内容不得包含 API Key、鉴权 Header 或完整错误体。</li></ul><h2 id="_3-信息架构" tabindex="-1">3. 信息架构 <a class="header-anchor" href="#_3-信息架构" aria-label="Permalink to &quot;3. 信息架构&quot;">​</a></h2>',14)),(e(),d(c,null,{default:i(()=>[r(t,{id:"mermaid-145",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%E6%B8%A0%E9%81%93%E7%BC%96%E8%BE%91%5D%20--%3E%20B%5B%E6%A8%A1%E5%9E%8B%E5%88%97%E8%A1%A8%5D%0A%20%20B%20--%3E%7C%E6%A3%80%E6%9F%A5%E5%85%A5%E5%8F%A3%7C%20C%5B%E6%A8%A1%E5%9E%8B%E6%A3%80%E6%9F%A5%E4%BB%BB%E5%8A%A1%E9%A1%B5%5D%0A%20%20B%20--%3E%7C%E5%8D%95%E6%A8%A1%E5%9E%8B%E7%8A%B6%E6%80%81%E6%88%96%E6%9B%B4%E5%A4%9A%E8%8F%9C%E5%8D%95%7C%20C%0A%20%20C%20--%3E%20D%5B%E9%80%89%E6%8B%A9%E6%A8%A1%E5%9E%8B%5D%0A%20%20C%20--%3E%20E%5B%E6%A3%80%E6%9F%A5%E9%80%89%E9%A1%B9%5D%0A%20%20D%20--%3E%20F%5B%E8%BF%90%E8%A1%8C%E4%B8%AD%5D%0A%20%20E%20--%3E%20F%0A%20%20F%20--%3E%7C%E5%81%9C%E6%AD%A2%7C%20G%5B%E9%83%A8%E5%88%86%E5%AE%8C%E6%88%90%E7%BB%93%E6%9E%9C%5D%0A%20%20F%20--%3E%7C%E5%85%A8%E9%83%A8%E5%AE%8C%E6%88%90%7C%20H%5B%E6%A3%80%E6%9F%A5%E7%BB%93%E6%9E%9C%5D%0A%20%20H%20--%3E%20I%5B%E5%A4%B1%E8%B4%A5%E7%AD%9B%E9%80%89%5D%0A%20%20H%20--%3E%20J%5B%E5%8D%95%E6%A8%A1%E5%9E%8B%E8%AF%8A%E6%96%AD%E8%AF%A6%E6%83%85%5D%0A%20%20I%20--%3E%7C%E9%87%8D%E8%AF%95%E5%A4%B1%E8%B4%A5%E9%A1%B9%7C%20F%0A%20%20J%20--%3E%7C%E9%87%8D%E8%AF%95%E6%AD%A4%E6%A8%A1%E5%9E%8B%7C%20F%0A"})]),fallback:i(()=>[...a[0]||(a[0]=[p(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=l(`<p>建议不新增持久化路由。检查任务页作为 <code>ProfileEditor</code> 内的原生 Vue 全屏任务层存在，直接持有未保存渠道快照；不要使用 <code>var-popup</code> 作为页面骨架。Varlet 只用于按钮、复选框、开关、进度等叶子控件。</p><h2 id="_4-入口设计" tabindex="-1">4. 入口设计 <a class="header-anchor" href="#_4-入口设计" aria-label="Permalink to &quot;4. 入口设计&quot;">​</a></h2><h3 id="_4-1-批量入口" tabindex="-1">4.1. 批量入口 <a class="header-anchor" href="#_4-1-批量入口" aria-label="Permalink to &quot;4.1. 批量入口&quot;">​</a></h3><p>模型列表标题调整为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模型 12                         [检查] [更多]</span></span></code></pre></div><ul><li>“检查”使用 <code>ScanSearch</code> 或项目当前 Lucide 图标族中的等价图标，并带文字，模型为空时禁用。</li><li>“更多”打开操作菜单，承载“从 API 获取”“手动添加”“清空模型”。</li><li>不再在窄屏标题行横排三个文字按钮，避免 320px 至 375px 屏幕换行。</li></ul><h3 id="_4-2-单模型入口" tabindex="-1">4.2. 单模型入口 <a class="header-anchor" href="#_4-2-单模型入口" aria-label="Permalink to &quot;4.2. 单模型入口&quot;">​</a></h3><p>模型行不再继续增加第三个圆形图标。建议将编辑和删除收进模型行的“更多”菜单，并提供：</p><ul><li>检查模型</li><li>编辑模型</li><li>删除模型</li></ul><p>模型行底部显示最近一次运行态摘要：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GPT-4.1 mini</span></span>
<span class="line"><span>gpt-4.1-mini</span></span>
<span class="line"><span>Chat                 检查成功  824 ms  &gt;</span></span></code></pre></div><p>点击结果摘要进入检查页并默认只选中当前模型。尚未检查时显示“尚未检查”，仍可点击进入。</p><h3 id="_4-3-与模型获取的语义区分" tabindex="-1">4.3. 与模型获取的语义区分 <a class="header-anchor" href="#_4-3-与模型获取的语义区分" aria-label="Permalink to &quot;4.3. 与模型获取的语义区分&quot;">​</a></h3><ul><li>“从 API 获取”会拉取模型列表并进入导入流程。</li><li>“模型检查”会发起最小真实推理请求并产生结构化诊断。</li><li>模型列表获取成功不得显示成“模型可用”或复用推理检查的成功状态。</li></ul><h2 id="_5-模型检查任务页" tabindex="-1">5. 模型检查任务页 <a class="header-anchor" href="#_5-模型检查任务页" aria-label="Permalink to &quot;5. 模型检查任务页&quot;">​</a></h2><h3 id="_5-1-页面骨架" tabindex="-1">5.1. 页面骨架 <a class="header-anchor" href="#_5-1-页面骨架" aria-label="Permalink to &quot;5.1. 页面骨架&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────┐</span></span>
<span class="line"><span>│ ‹  模型检查                 重置 │</span></span>
<span class="line"><span>├────────────────────────────────┤</span></span>
<span class="line"><span>│ 搜索模型                       │</span></span>
<span class="line"><span>│ [全部] [可检查] [失败]           │</span></span>
<span class="line"><span>│ 已选 8/12              全选/取消 │</span></span>
<span class="line"><span>├────────────────────────────────┤</span></span>
<span class="line"><span>│ □ GPT-4.1 mini           Chat   │</span></span>
<span class="line"><span>│   gpt-4.1-mini        上次 824ms │</span></span>
<span class="line"><span>│ ────────────────────────────── │</span></span>
<span class="line"><span>│ □ text-embedding-3       向量    │</span></span>
<span class="line"><span>│   text-embedding-3-small 尚未检查 │</span></span>
<span class="line"><span>│ ────────────────────────────── │</span></span>
<span class="line"><span>│ □ image-1               图片  ¥  │</span></span>
<span class="line"><span>│   需要付费确认                   │</span></span>
<span class="line"><span>│                                │</span></span>
<span class="line"><span>├────────────────────────────────┤</span></span>
<span class="line"><span>│ [选项]              [检查 8 个模型]│</span></span>
<span class="line"><span>└────────────────────────────────┘</span></span></code></pre></div><p>页面由原生 <code>header</code>、滚动内容区和安全区底部操作栏组成。底部操作栏使用 <code>env(safe-area-inset-bottom)</code>，不得遮挡最后一行内容。</p><h3 id="_5-2-选择区" tabindex="-1">5.2. 选择区 <a class="header-anchor" href="#_5-2-选择区" aria-label="Permalink to &quot;5.2. 选择区&quot;">​</a></h3><ul><li>搜索匹配模型名称和 ID，输入使用本地过滤，不影响选择状态。</li><li>顶部使用分段控制切换“全部”“可检查”“失败”。首轮无结果时隐藏“失败”。</li><li>分组沿用模型现有 group，但检查页默认展开所有命中分组。</li><li>每行点击整行切换选择，复选框触控区至少 44 x 44px。</li><li>“全选”只选择当前过滤范围内可检查的模型。</li><li>视频、音乐行不可选择，状态为“不支持自动检查”。</li><li>图片、音频可以选择，但显示“需要付费确认”，不得用普通能力标签弱化成本提示。</li></ul><h3 id="_5-3-检查选项" tabindex="-1">5.3. 检查选项 <a class="header-anchor" href="#_5-3-检查选项" aria-label="Permalink to &quot;5.3. 检查选项&quot;">​</a></h3><p>底部“选项”按钮打开自研底部面板，包含：</p><table tabindex="0"><thead><tr><th>选项</th><th>控件</th><th>展示条件</th><th>默认值</th></tr></thead><tbody><tr><td>并发数</td><td><code>1 / 2 / 3 / 4</code> 分段控制</td><td>选择两个及以上模型</td><td>3</td></tr><tr><td>流式 Chat</td><td>开关</td><td>已选模型包含 Chat</td><td>关闭</td></tr><tr><td>超时</td><td>菜单</td><td>始终显示</td><td>60 秒</td></tr></tbody></table><p>并发上限建议为 4。移动设备网络和 WebView 资源更有限，没有必要暴露桌面端的 8 并发上限。</p><p>图片和音频的付费授权不设计成可长期保留的开关。点击开始检查时，如果选择中包含付费能力，弹出一次性确认面板：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>本次包含 2 个付费媒体模型</span></span>
<span class="line"><span></span></span>
<span class="line"><span>检查会向上游发送真实生成请求，可能产生费用。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[返回调整]  [确认并检查]</span></span></code></pre></div><p>授权仅对本次运行有效。视频和音乐不会出现在确认范围内，因为首批不执行这两类探测。</p><h2 id="_6-运行中状态" tabindex="-1">6. 运行中状态 <a class="header-anchor" href="#_6-运行中状态" aria-label="Permalink to &quot;6. 运行中状态&quot;">​</a></h2><h3 id="_6-1-固定进度区" tabindex="-1">6.1. 固定进度区 <a class="header-anchor" href="#_6-1-固定进度区" aria-label="Permalink to &quot;6.1. 固定进度区&quot;">​</a></h3><p>运行开始后，选择控件变为只读，顶部显示：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正在检查  5/12</span></span>
<span class="line"><span>成功 3   失败 1   运行中 1   等待 7</span></span></code></pre></div><p>可使用线性进度条表达真实完成比例。进度变化写入 <code>aria-live=&quot;polite&quot;</code>，但避免每个网络事件都播报，只在完成数变化时更新。</p><h3 id="_6-2-行状态" tabindex="-1">6.2. 行状态 <a class="header-anchor" href="#_6-2-行状态" aria-label="Permalink to &quot;6.2. 行状态&quot;">​</a></h3><p>结果顺序保持用户选择时的模型顺序，不按完成时间跳动。</p><table tabindex="0"><thead><tr><th>状态</th><th>图标与文字</th><th>行内信息</th></tr></thead><tbody><tr><td>等待</td><td><code>Clock</code> + 等待中</td><td>不显示假进度</td></tr><tr><td>运行</td><td><code>LoaderCircle</code> + 检查中</td><td>显示已用时间</td></tr><tr><td>成功</td><td><code>CircleCheck</code> + 成功</td><td>总耗时、TTFB</td></tr><tr><td>失败</td><td><code>CircleX</code> + 失败</td><td>本地化错误分类与短摘要</td></tr><tr><td>停止</td><td><code>Square</code> + 已停止</td><td>区分在途取消和未执行</td></tr><tr><td>不支持</td><td><code>Ban</code> + 不支持</td><td>显示能力原因</td></tr></tbody></table><p>颜色使用现有 <code>--success-color</code>、<code>--warning-color</code>、<code>--danger-color</code> 和文本 token，不另建一套探测品牌色。</p><h3 id="_6-3-停止与离开" tabindex="-1">6.3. 停止与离开 <a class="header-anchor" href="#_6-3-停止与离开" aria-label="Permalink to &quot;6.3. 停止与离开&quot;">​</a></h3><ul><li>底部主按钮切换为“停止检查”，使用危险语义但不使用强烈常驻红底，可采用描边按钮。</li><li>停止后保留已完成结果，在途请求标记“已停止”，未开始项标记“未执行”。</li><li>运行时点击返回或系统返回键，弹出“退出将停止本次检查”。操作为“继续检查”和“停止并退出”。</li><li>首批不做后台检查。页面卸载必须触发同一个批量 <code>AbortController</code>。</li></ul><h2 id="_7-结果状态" tabindex="-1">7. 结果状态 <a class="header-anchor" href="#_7-结果状态" aria-label="Permalink to &quot;7. 结果状态&quot;">​</a></h2><h3 id="_7-1-汇总区" tabindex="-1">7.1. 汇总区 <a class="header-anchor" href="#_7-1-汇总区" aria-label="Permalink to &quot;7.1. 汇总区&quot;">​</a></h3><p>完成后顶部显示一行紧凑汇总，不使用大面积成功卡片：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>已完成 12 个模型    成功 9    失败 3</span></span></code></pre></div><p>下方分段控制为“全部”“失败”“成功”。如果存在失败，默认切换到“失败”，帮助用户直接处理问题。</p><p>底部操作栏提供：</p><ul><li>有失败时：“重试失败项”作为主按钮。</li><li>全部成功时：“再次检查”作为主按钮。</li><li>次按钮：“重新选择”。</li></ul><h3 id="_7-2-单项诊断详情" tabindex="-1">7.2. 单项诊断详情 <a class="header-anchor" href="#_7-2-单项诊断详情" aria-label="Permalink to &quot;7.2. 单项诊断详情&quot;">​</a></h3><p>点击结果行进入原生全屏详情层，不使用 Snackbar 承载诊断信息。详情结构：</p><ol><li>模型名称、ID、能力和检查时间。</li><li>状态摘要与面向用户的短错误说明。</li><li>指标：总耗时、TTFB、HTTP、Tokens。</li><li>诊断：阶段、稳定错误分类、已脱敏详情。</li><li>响应摘要或错误摘要，提供复制按钮。</li><li>底部“重试此模型”。</li></ol><p>阶段和分类同时保留本地化名称与稳定代码，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>响应校验</span></span>
<span class="line"><span>semantic-validation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>模型不可用</span></span>
<span class="line"><span>model-unavailable</span></span></code></pre></div><p>复制内容使用结构化纯文本，只包含模型 ID、能力、时间、HTTP、阶段、分类和脱敏摘要。</p><h2 id="_8-状态生命周期" tabindex="-1">8. 状态生命周期 <a class="header-anchor" href="#_8-状态生命周期" aria-label="Permalink to &quot;8. 状态生命周期&quot;">​</a></h2><h3 id="_8-1-结果保留" tabindex="-1">8.1. 结果保留 <a class="header-anchor" href="#_8-1-结果保留" aria-label="Permalink to &quot;8.1. 结果保留&quot;">​</a></h3><ul><li>结果只保留在当前 <code>ProfileEditor</code> 页面运行态，不跨应用重启。</li><li>返回渠道编辑后，模型行继续显示本次结果摘要。</li><li>再次进入检查页时保留选择和结果，用户可直接重试。</li></ul><h3 id="_8-2-配置变化" tabindex="-1">8.2. 配置变化 <a class="header-anchor" href="#_8-2-配置变化" aria-label="Permalink to &quot;8.2. 配置变化&quot;">​</a></h3><p>检查开始时生成不可变 Profile 快照。返回编辑页后，如果以下字段发生变化，已有结果显示“配置已变化”，再次进入时要求重新检查：</p><ul><li>Provider 类型</li><li>Base URL</li><li>API Key 集合</li><li>自定义 Header 或 Endpoint</li><li>代理、证书或 HTTP/1 配置</li><li>模型 ID 或能力</li></ul><p>实现时可比较不含明文 Key 的配置指纹。指纹只用于失效判断，不写入探测结果或日志。</p><h3 id="_8-3-key-健康" tabindex="-1">8.3. Key 健康 <a class="header-anchor" href="#_8-3-key-健康" aria-label="Permalink to &quot;8.3. Key 健康&quot;">​</a></h3><ul><li>模型检查不得直接写 <code>isBroken</code>。</li><li>不通过普通 <code>useLlmRequest.sendRequest()</code> 发起检查，因为它会重新读取已保存 Store，并自动写入 Key 健康状态。</li><li>如需上报 Key 健康，只允许由独立策略根据结构化结果执行一次动作。</li><li>用户取消、配置错误、模型不可用和能力不支持不污染 Key 健康状态。</li></ul><h2 id="_9-组件与状态边界" tabindex="-1">9. 组件与状态边界 <a class="header-anchor" href="#_9-组件与状态边界" aria-label="Permalink to &quot;9. 组件与状态边界&quot;">​</a></h2><p>建议组件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mobile/src/tools/llm-api/</span></span>
<span class="line"><span>├── components/</span></span>
<span class="line"><span>│   ├── ModelList.vue</span></span>
<span class="line"><span>│   └── probe/</span></span>
<span class="line"><span>│       ├── ModelProbeTaskPage.vue</span></span>
<span class="line"><span>│       ├── ModelProbeModelList.vue</span></span>
<span class="line"><span>│       ├── ModelProbeOptionsSheet.vue</span></span>
<span class="line"><span>│       ├── ModelProbeCostConfirm.vue</span></span>
<span class="line"><span>│       └── ModelProbeDetailPage.vue</span></span>
<span class="line"><span>├── composables/</span></span>
<span class="line"><span>│   └── useModelProbe.ts</span></span>
<span class="line"><span>└── probe/</span></span>
<span class="line"><span>    ├── types.ts</span></span>
<span class="line"><span>    ├── key-health-policy.ts</span></span>
<span class="line"><span>    └── channel-probe-service.ts</span></span></code></pre></div><p>职责划分：</p><table tabindex="0"><thead><tr><th>模块</th><th>职责</th></tr></thead><tbody><tr><td><code>ModelProbeTaskPage</code></td><td>页面阶段、选择、过滤、离开保护、底部动作</td></tr><tr><td><code>useModelProbe</code></td><td>结果字典、运行状态、进度、快照、取消和重试</td></tr><tr><td><code>channel-probe-service</code></td><td>Adapter、Executor、移动 Transport、TTFB 和批量并发</td></tr><tr><td><code>@aiohub/llm-core/probe</code></td><td>计划解析、语义校验、错误分类和共享结果契约</td></tr><tr><td><code>key-health-policy</code></td><td>将结构化结果映射成一次 Key 健康动作</td></tr></tbody></table><p>移动端服务应复用 <code>mobileLlmTransport</code> 的 observer 和 <code>AbortSignal</code>，不要复制 URL、Header、请求体或流式解析逻辑。</p><h2 id="_10-视觉与交互规格" tabindex="-1">10. 视觉与交互规格 <a class="header-anchor" href="#_10-视觉与交互规格" aria-label="Permalink to &quot;10. 视觉与交互规格&quot;">​</a></h2><ul><li>页面背景使用 <code>--color-surface</code> 或 AIO 主题对应 token。</li><li>底部栏使用 <code>--container-bg</code> 和 <code>backdrop-filter: blur(var(--ui-blur))</code>。</li><li>输入使用 <code>--input-bg</code>，分隔线使用 <code>--border-color</code>。</li><li>圆角使用 <code>--app-radius-md</code> 和 <code>--app-radius-lg</code>，不新增固定 20px 大圆角体系。</li><li>模型列表使用分隔线和留白组织，不给每个结果再包一层装饰卡片。</li><li>最小触控目标为 44 x 44px。</li><li>模型 ID、稳定错误码使用等宽字体，正文继续使用项目字体。</li><li>只对 <code>transform</code> 和 <code>opacity</code> 做 150ms 至 200ms 状态转场。</li><li><code>prefers-reduced-motion</code> 下关闭旋转以外的非必要转场，运行状态仍通过文字更新。</li><li>所有图标按钮提供 <code>aria-label</code>，进度和结果汇总提供可读文本。</li><li>用户提示通过 <code>customMessage</code> 和 <code>customDialog</code> 封装，不在新增业务代码中直接调用 <code>Snackbar</code> 或 <code>Dialog</code>。</li></ul><h2 id="_11-必备状态" tabindex="-1">11. 必备状态 <a class="header-anchor" href="#_11-必备状态" aria-label="Permalink to &quot;11. 必备状态&quot;">​</a></h2><p>实现必须覆盖：</p><ul><li>无模型：解释需要先添加模型，主动作“从 API 获取”。</li><li>无选择：底部主按钮禁用，并显示“请选择至少一个可检查模型”。</li><li>全部不支持：展示能力原因，不允许开始。</li><li>运行中：真实进度、停止、离开保护。</li><li>部分成功：保留成功结果，默认聚焦失败项。</li><li>全部成功：显示汇总与再次检查入口。</li><li>全部失败：显示失败分类分布和重试入口。</li><li>用户取消：区分已完成、已停止和未执行。</li><li>配置已变化：旧结果标记过期，不与新快照混用。</li><li>页面恢复：应用回到前台后继续展示真实任务状态，不伪造完成。</li></ul><h2 id="_12-首批范围与后续范围" tabindex="-1">12. 首批范围与后续范围 <a class="header-anchor" href="#_12-首批范围与后续范围" aria-label="Permalink to &quot;12. 首批范围与后续范围&quot;">​</a></h2><h3 id="首批必须实现" tabindex="-1">首批必须实现 <a class="header-anchor" href="#首批必须实现" aria-label="Permalink to &quot;首批必须实现&quot;">​</a></h3><ul><li>单模型和批量检查。</li><li>搜索、全选、可检查筛选和结果筛选。</li><li>并发 1 至 4、Chat 流式开关、60 秒默认超时。</li><li>批量取消和离开保护。</li><li>图片、音频一次性成本确认。</li><li>视频、音乐明确不支持。</li><li>结构化详情、复制脱敏诊断、单项重试和失败重试。</li><li>当前渠道编辑会话内的结果回显与配置变化失效。</li></ul><h3 id="暂不实现" tabindex="-1">暂不实现 <a class="header-anchor" href="#暂不实现" aria-label="Permalink to &quot;暂不实现&quot;">​</a></h3><ul><li>跨重启持久化历史。</li><li>后台周期检查和系统通知。</li><li>自动禁用整个渠道。</li><li>视频、音乐自动探测。</li><li>跨渠道批量检查。</li></ul><h2 id="_13-验收标准" tabindex="-1">13. 验收标准 <a class="header-anchor" href="#_13-验收标准" aria-label="Permalink to &quot;13. 验收标准&quot;">​</a></h2><h3 id="交互" tabindex="-1">交互 <a class="header-anchor" href="#交互" aria-label="Permalink to &quot;交互&quot;">​</a></h3><ul><li>320px 宽度下标题、筛选和底部按钮不横向溢出。</li><li>单模型从模型列表进入时默认只选择该模型。</li><li>批量结果顺序稳定，不因请求完成顺序跳动。</li><li>停止会终止在途请求并阻止后续任务启动。</li><li>返回手势和系统返回键在运行中都触发离开保护。</li><li>付费媒体未确认时绝不发送请求。</li></ul><h3 id="语义" tabindex="-1">语义 <a class="header-anchor" href="#语义" aria-label="Permalink to &quot;语义&quot;">​</a></h3><ul><li>“从 API 获取”和“模型检查”不会共用成功文案或结果状态。</li><li>失败分类、阶段、HTTP、TTFB、Usage 和响应摘要可在详情中查看。</li><li>不支持能力不会回退到 Chat。</li><li>配置变化后旧结果明确标记过期。</li></ul><h3 id="安全与可访问性" tabindex="-1">安全与可访问性 <a class="header-anchor" href="#安全与可访问性" aria-label="Permalink to &quot;安全与可访问性&quot;">​</a></h3><ul><li>UI、日志和复制诊断中没有明文 Key 或鉴权 Header。</li><li>状态不用颜色单独表达。</li><li>触控目标、对比度、屏幕阅读器标签和动态播报满足移动端基本可访问性要求。</li><li>深色、浅色和用户自定义主题下均使用项目 token，不出现固定白底或黑底。</li></ul><h2 id="_14-实现顺序建议" tabindex="-1">14. 实现顺序建议 <a class="header-anchor" href="#_14-实现顺序建议" aria-label="Permalink to &quot;14. 实现顺序建议&quot;">​</a></h2><ol><li>先完成移动端 Probe Service、快照、取消和自动化测试。</li><li>再完成 <code>useModelProbe</code> 状态机与无 UI 单测。</li><li>接入全屏任务页、选择和运行态。</li><li>接入详情、复制诊断、结果筛选和重试。</li><li>最后改造模型列表入口与运行态摘要，并补移动端生产构建验证。</li></ol>`,85))])}const k=s(h,[["render",u]]);export{x as __pageData,k as default};
